+fn first_glob_index(s: &str) -> Option<usize> {
+    let mut best = None;
+    for c in ['*', '?', '[', '{'] {
+        if let Some(idx) = s.find(c) {
+            match best {
+                None => best = Some(idx),
+                Some(current) => {
+                    if idx < current {
+                        best = Some(idx);
+                    }
+                }
+            }
+        }
+    }
+    best
+}
